import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val graph = mutable.HashMap[Long, List[(Long, Long)]]()
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    if (!graph.contains(u)) graph(u) = List()
    if (!graph.contains(v)) graph(v) = List()
    graph(u) = (v, w) :: graph(u)
    graph(v) = (u, w) :: graph(v)
  }

  val parent = mutable.ArrayBuffer.fill(n.toInt)(0L)
  val rank = mutable.ArrayBuffer.fill(n.toInt)(1L)

  def find(u: Long): Long = {
    var uRoot = u
    while (parent(uRoot) != uRoot) {
      parent(uRoot) = parent(parent(uRoot))
      uRoot = parent(uRoot)
    }
    uRoot
  }

  def union(u: Long, v: Long): Boolean = {
    val uRoot = find(u)
    val vRoot = find(v)
    if (uRoot == vRoot) return false
    if (rank(uRoot) < rank(vRoot)) {
      parent(uRoot) = vRoot
      rank(vRoot) += rank(uRoot)
    } else {
      parent(vRoot) = uRoot
      rank(uRoot) += rank(vRoot)
    }
    true
  }

  val maxHeap = mutable.PriorityQueue[(-Long, Long)]()
  for (i <- 0 until n.toInt) {
    maxHeap += (-0L, i)
  }

  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    val uRoot = find(u)
    val vRoot = find(v)
    if (uRoot != vRoot) {
      maxHeap += (-w, uRoot)
      union(u, v)
    }
  }

  val maxCosts = mutable.ListBuffer[Long]()
  while (maxHeap.nonEmpty) {
    val (cost, _) = maxHeap.pop()
    maxCosts += -cost
  }

  if (n - k >= 1) maxCosts(n - k - 1) else 0L
}
